// frontend/src/pages/Dashboard.js
import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import PlaceCard from '../components/PlaceCard';
import CheckoutModal from '../components/CheckoutModal';
import AddPlaceModal from '../components/AddPlaceModal';
import Analytics from '../components/Analytics';
import Toast from '../components/Toast';
import {
  getPlaces, getPrediction, checkIn, checkOut,
  getMyActiveCheckin,
} from '../services/api';

const CATEGORIES = [
  { key: 'all',        label: 'All Places', icon: '🗺️' },
  { key: 'mall',       label: 'Malls',      icon: '🛍️' },
  { key: 'cafe',       label: 'Cafes',      icon: '☕' },
  { key: 'gym',        label: 'Gyms',       icon: '💪' },
  { key: 'restaurant', label: 'Restaurants',icon: '🍽️' },
];

const TABS = ['Explore', 'Analytics', 'Profile'];

export default function Dashboard() {
  const { user, logout } = useAuth();

  const [places, setPlaces]         = useState([]);
  const [predictions, setPred]      = useState({});
  const [category, setCategory]     = useState('all');
  const [search, setSearch]         = useState('');
  const [activeCheckin, setActiveCI]= useState(null);
  const [checkoutModal, setCheckout]= useState(null);
  const [addModal, setAddModal]     = useState(false);
  const [toast, setToast]           = useState(null);
  const [locStatus, setLocStatus]   = useState('');
  const [loading, setLoading]       = useState(true);
  const [tab, setTab]               = useState('Explore');
  const [sidebarOpen, setSidebar]   = useState(false);

  const showToast = (message, type = 'success') => setToast({ message, type });

  const loadPlaces = useCallback(async (cat, q) => {
    setLoading(true);
    try {
      const data = await getPlaces(cat, q);
      setPlaces(data);
      const predEntries = await Promise.all(
        data.map(p => getPrediction(p.id).then(pred => [p.id, pred]))
      );
      setPred(Object.fromEntries(predEntries));
    } catch {
      showToast('Could not load places. Make sure the backend is running.', 'error');
    } finally {
      setLoading(false);
    }
  }, []);

  const loadActiveCheckin = useCallback(async () => {
    try { setActiveCI(await getMyActiveCheckin()); }
    catch { setActiveCI(null); }
  }, []);

  useEffect(() => { loadPlaces('all', ''); loadActiveCheckin(); }, []);
  useEffect(() => {
    const t = setTimeout(() => loadPlaces(category, search), 400);
    return () => clearTimeout(t);
  }, [search, category]);

  const detectLocation = () => {
    if (!navigator.geolocation) { showToast('Geolocation not supported', 'error'); return; }
    setLocStatus('Detecting your location...');
    navigator.geolocation.getCurrentPosition(
      pos => {
        setLocStatus(`📍 ${pos.coords.latitude.toFixed(4)}, ${pos.coords.longitude.toFixed(4)}`);
        showToast('Location detected successfully!');
      },
      () => {
        setLocStatus('Location access denied');
        showToast('Could not access location. Please allow permission.', 'error');
      }
    );
  };

  const handleCheckin = async (place_id) => {
    try {
      const res = await checkIn(place_id);
      showToast(res.message || 'Checked in successfully!');
      await loadActiveCheckin();
    } catch (err) {
      showToast(err.response?.data?.error || 'Check-in failed', 'error');
    }
  };

  const handleCheckout = (place_id) => {
    const place = places.find(p => p.id === place_id);
    setCheckout({ place_id, place_name: place?.name || 'this place' });
  };

  const handleCostSubmit = async (amount) => {
    try {
      const res = await checkOut(checkoutModal.place_id, amount);
      showToast(res.message || 'Checked out successfully!');
      setCheckout(null);
      await loadActiveCheckin();
      await loadPlaces(category, search);
    } catch (err) {
      showToast(err.response?.data?.error || 'Checkout failed', 'error');
      setCheckout(null);
    }
  };

  const handlePlaceAdded = (newPlace) => {
    showToast(`"${newPlace.name}" added successfully!`);
    loadPlaces(category, search);
  };

  // ── Styles ────────────────────────────────────────────
  const s = {
    page:    { minHeight: '100vh', background: '#f4f5f7', display: 'flex', flexDirection: 'column' },
    nav: {
      background: '#fff', borderBottom: '1px solid #eee',
      padding: '0 24px', height: '64px', display: 'flex',
      alignItems: 'center', justifyContent: 'space-between',
      position: 'sticky', top: 0, zIndex: 100,
    },
    logo:    { fontSize: '20px', fontWeight: '800', color: '#1a1a2e', letterSpacing: '-0.5px' },
    logoG:   { color: '#1D9E75' },
    navTabs: { display: 'flex', gap: '4px' },
    navTab: (active) => ({
      padding: '8px 18px', border: 'none', background: active ? '#e8f8f2' : 'transparent',
      color: active ? '#0f6e56' : '#888', borderRadius: '10px',
      fontSize: '14px', fontWeight: active ? '700' : '500', cursor: 'pointer',
    }),
    navRight: { display: 'flex', alignItems: 'center', gap: '10px' },
    avatar: {
      width: '36px', height: '36px', borderRadius: '50%',
      background: 'linear-gradient(135deg, #1D9E75, #0f6e56)',
      color: '#fff', display: 'flex', alignItems: 'center',
      justifyContent: 'center', fontWeight: '700', fontSize: '14px',
    },
    logoutBtn: {
      padding: '7px 14px', border: '1.5px solid #eee', background: '#fff',
      color: '#888', borderRadius: '8px', fontSize: '13px', cursor: 'pointer',
    },
    main:    { maxWidth: '1200px', margin: '0 auto', padding: '24px 20px', width: '100%' },
    searchRow: { display: 'flex', gap: '10px', marginBottom: '16px', flexWrap: 'wrap' },
    searchBox: {
      flex: 1, minWidth: '220px', padding: '12px 18px',
      border: '1.5px solid #e8e8e8', borderRadius: '14px',
      fontSize: '14px', outline: 'none', background: '#fff',
      boxShadow: '0 2px 8px rgba(0,0,0,0.04)',
    },
    locBtn: {
      padding: '12px 18px', background: '#1a1a2e', color: '#fff',
      border: 'none', borderRadius: '14px', fontSize: '13px',
      fontWeight: '600', cursor: 'pointer', whiteSpace: 'nowrap',
    },
    addBtn: {
      padding: '12px 18px', background: 'linear-gradient(135deg, #1D9E75, #0f6e56)',
      color: '#fff', border: 'none', borderRadius: '14px',
      fontSize: '13px', fontWeight: '600', cursor: 'pointer', whiteSpace: 'nowrap',
    },
    catRow: { display: 'flex', gap: '8px', marginBottom: '20px', flexWrap: 'wrap' },
    catBtn: (active) => ({
      padding: '8px 16px', display: 'flex', alignItems: 'center', gap: '6px',
      border: '1.5px solid ' + (active ? '#1D9E75' : '#e8e8e8'),
      borderRadius: '40px', background: active ? '#e8f8f2' : '#fff',
      color: active ? '#0f6e56' : '#666', fontSize: '13px',
      fontWeight: active ? '700' : '500', cursor: 'pointer', transition: 'all .15s',
    }),
    activeBar: {
      background: 'linear-gradient(135deg, #e8f8f2, #d4f0e4)',
      border: '1.5px solid #1D9E75', borderRadius: '14px',
      padding: '14px 18px', marginBottom: '20px',
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    },
    checkoutBtn: {
      padding: '8px 16px', background: '#c0392b', color: '#fff',
      border: 'none', borderRadius: '10px', fontSize: '13px',
      fontWeight: '700', cursor: 'pointer',
    },
    grid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
      gap: '16px',
    },
    emptyState: {
      textAlign: 'center', padding: '80px 20px', color: '#bbb',
    },
  };

  return (
    <div style={s.page}>
      {/* Navbar */}
      <nav style={s.nav}>
        <div style={s.logo}>Visit<span style={s.logoG}>Wise</span> AI</div>

        <div style={s.navTabs}>
          {TABS.map(t => (
            <button key={t} style={s.navTab(tab === t)} onClick={() => setTab(t)}>
              {t}
            </button>
          ))}
        </div>

        <div style={s.navRight}>
          <div style={s.avatar}>{user?.name?.charAt(0).toUpperCase()}</div>
          <span style={{ fontSize: '14px', fontWeight: '600', color: '#1a1a2e' }}>
            {user?.name?.split(' ')[0]}
          </span>
          <button style={s.logoutBtn} onClick={logout}>Sign Out</button>
        </div>
      </nav>

      <div style={s.main}>

        {/* ── EXPLORE TAB ── */}
        {tab === 'Explore' && (
          <>
            {/* Search row */}
            <div style={s.searchRow}>
              <input
                style={s.searchBox} placeholder="🔍  Search malls, cafes, gyms..."
                value={search} onChange={e => setSearch(e.target.value)}
              />
              <button style={s.locBtn} onClick={detectLocation}>📍 Detect Location</button>
              <button style={s.addBtn} onClick={() => setAddModal(true)}>+ Add Place</button>
            </div>

            {/* Location status */}
            {locStatus && (
              <div style={{ fontSize: '12px', color: '#888', marginBottom: '14px' }}>
                {locStatus}
              </div>
            )}

            {/* Category filter */}
            <div style={s.catRow}>
              {CATEGORIES.map(c => (
                <button key={c.key} style={s.catBtn(category === c.key)} onClick={() => setCategory(c.key)}>
                  <span>{c.icon}</span>{c.label}
                </button>
              ))}
            </div>

            {/* Active check-in banner */}
            {activeCheckin && (
              <div style={s.activeBar}>
                <div>
                  <div style={{ fontSize: '13px', fontWeight: '700', color: '#0f6e56' }}>
                    ✅ You are currently at
                  </div>
                  <div style={{ fontSize: '16px', fontWeight: '800', color: '#1a1a2e', marginTop: '2px' }}>
                    {activeCheckin.place_name}
                  </div>
                </div>
                <button
                  style={s.checkoutBtn}
                  onClick={() => handleCheckout(activeCheckin.place_id)}
                >Check Out</button>
              </div>
            )}

            {/* Places grid */}
            {loading ? (
              <div style={s.emptyState}>
                <div style={{ fontSize: '36px', marginBottom: '12px' }}>⏳</div>
                <div style={{ fontWeight: '600' }}>Loading places...</div>
              </div>
            ) : places.length === 0 ? (
              <div style={s.emptyState}>
                <div style={{ fontSize: '48px', marginBottom: '16px' }}>🔍</div>
                <div style={{ fontWeight: '700', fontSize: '16px', color: '#888' }}>No places found</div>
                <div style={{ fontSize: '13px', marginTop: '6px' }}>
                  Try a different search or <span style={{ color: '#1D9E75', cursor: 'pointer', fontWeight: '600' }} onClick={() => setAddModal(true)}>add a new place</span>
                </div>
              </div>
            ) : (
              <div style={s.grid}>
                {places.map(place => (
                  <PlaceCard
                    key={place.id}
                    place={place}
                    prediction={predictions[place.id]}
                    isCheckedIn={activeCheckin?.place_id === place.id}
                    onCheckin={handleCheckin}
                    onCheckout={handleCheckout}
                  />
                ))}
              </div>
            )}
          </>
        )}

        {/* ── ANALYTICS TAB ── */}
        {tab === 'Analytics' && <Analytics />}

        {/* ── PROFILE TAB ── */}
        {tab === 'Profile' && (
          <div style={{ maxWidth: '480px', margin: '0 auto' }}>
            <div style={{ background: '#fff', borderRadius: '20px', padding: '32px', border: '1.5px solid #f0f0f0', textAlign: 'center' }}>
              <div style={{
                width: '80px', height: '80px', borderRadius: '50%', margin: '0 auto 16px',
                background: 'linear-gradient(135deg, #1D9E75, #0f6e56)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: '32px', fontWeight: '800', color: '#fff',
              }}>
                {user?.name?.charAt(0).toUpperCase()}
              </div>
              <h2 style={{ fontSize: '22px', fontWeight: '800', color: '#1a1a2e', margin: '0 0 6px' }}>{user?.name}</h2>
              <p style={{ color: '#999', fontSize: '14px', margin: '0 0 28px' }}>{user?.email}</p>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '28px' }}>
                {[
                  { label: 'Member Since', value: user?.created_at ? new Date(user.created_at).toLocaleDateString('en-IN', { month: 'long', year: 'numeric' }) : 'Today' },
                  { label: 'Account Status', value: 'Active ✓' },
                ].map(s => (
                  <div key={s.label} style={{ background: '#f7f8fc', borderRadius: '12px', padding: '14px' }}>
                    <div style={{ fontSize: '11px', color: '#bbb', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '4px' }}>{s.label}</div>
                    <div style={{ fontSize: '14px', fontWeight: '700', color: '#1a1a2e' }}>{s.value}</div>
                  </div>
                ))}
              </div>

              <button onClick={logout} style={{
                width: '100%', padding: '13px',
                background: '#fdecea', color: '#c0392b',
                border: '1.5px solid #fcd5d2', borderRadius: '12px',
                fontSize: '14px', fontWeight: '700', cursor: 'pointer',
              }}>
                Sign Out
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Modals */}
      {checkoutModal && (
        <CheckoutModal
          placeName={checkoutModal.place_name}
          onSubmit={handleCostSubmit}
          onClose={() => setCheckout(null)}
        />
      )}
      {addModal && (
        <AddPlaceModal
          onClose={() => setAddModal(false)}
          onAdded={handlePlaceAdded}
        />
      )}
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
}
